            // A few useful managed helpers for common patterns

            // Convert ada_text to managed UTF-8 string (frees native buffer returned by ada_text_to_utf8)
            public static string AdaTextToManagedString(ref ada_text text)
            {
                ada_text t = text;
                ada_text_to_utf8(ref t, out IntPtr bytesPtr, out UIntPtr len);
                if (bytesPtr == IntPtr.Zero || len == UIntPtr.Zero) return string.Empty;
                try
                {
                    int length = (int)len;
                    byte[] buffer = new byte[length];
                    Marshal.Copy(bytesPtr, buffer, 0, length);
                    return Encoding.UTF8.GetString(buffer);
                }
                finally
                {
                    if (bytesPtr != IntPtr.Zero) ada_free(bytesPtr);
                }
            }

            // Convert ada_symbol_type to managed string (calls ada_symbol_text then AdaTextToManagedString)
            public static string AdaSymbolToString(ref ada_symbol_type sym)
            {
                ada_text text;
                ada_symbol_text(ref sym, out text);
                try
                {
                    return AdaTextToManagedString(ref text);
                }
                finally
                {
                    // ada_symbol_text returns an ada_text that may own buffer; free if allocated
                    ada_destroy_text(ref text);
                }
            }

            // Convert ada_string_type handle to UTF-8 managed string (frees bytes returned by ada_string_to_utf8)
            public static string AdaStringHandleToUtf8(IntPtr adaStringHandle)
            {
                if (adaStringHandle == IntPtr.Zero) return null;
                ada_string_to_utf8(adaStringHandle, out IntPtr bytes, out UIntPtr len);
                try
                {
                    if (bytes == IntPtr.Zero || len == UIntPtr.Zero) return string.Empty;
                    int length = (int)len;
                    byte[] buffer = new byte[length];
                    Marshal.Copy(bytes, buffer, 0, length);
                    return Encoding.UTF8.GetString(buffer);
                }
                finally
                {
                    if (bytes != IntPtr.Zero) ada_free(bytes);
                }
            }
        }
