        // Small array struct reader helpers (assumes libadalang array layout: int length; pointer c_ptr)
        public static ada_node[] ReadNodeArrayAndFree(IntPtr arrPtr)
        {
            if (arrPtr == IntPtr.Zero) return Array.Empty<ada_node>();
            try
            {
                int length = Marshal.ReadInt32(arrPtr);
                IntPtr cptr = Marshal.ReadIntPtr(arrPtr, IntPtr.Size); // offset of pointer on x64
                if (cptr == IntPtr.Zero || length == 0) return Array.Empty<ada_node>();
                ada_node[] result = new ada_node[length];
                int elemSize = Marshal.SizeOf<ada_node>();
                for (int i = 0; i < length; ++i)
                {
                    IntPtr elemPtr = new IntPtr(cptr.ToInt64() + i * elemSize);
                    result[i] = Marshal.PtrToStructure<ada_node>(elemPtr);
                }
                return result;
            }
            finally
            {
                ada_node_array_dec_ref(arrPtr);
            }
        }

        public static ada_symbol_type[] ReadSymbolTypeArrayAndFree(IntPtr arrPtr)
        {
            if (arrPtr == IntPtr.Zero) return Array.Empty<ada_symbol_type>();
            try
            {
                int length = Marshal.ReadInt32(arrPtr);
                IntPtr cptr = Marshal.ReadIntPtr(arrPtr, IntPtr.Size);
                if (cptr == IntPtr.Zero || length == 0) return Array.Empty<ada_symbol_type>();
                ada_symbol_type[] result = new ada_symbol_type[length];
                int elemSize = Marshal.SizeOf<ada_symbol_type>();
                for (int i = 0; i < length; ++i)
                {
                    IntPtr elemPtr = new IntPtr(cptr.ToInt64() + i * elemSize);
                    result[i] = Marshal.PtrToStructure<ada_symbol_type>(elemPtr);
                }
                return result;
            }
            finally
            {
                // symbol arrays often have dec_ref helpers named ada_symbol_type_array_dec_ref in the header;
                // if such exists add DllImport and call here. Fallback: try to call ada_free on pointer block.
                ada_free(arrPtr);
            }
        }

        // Enumerate node iterator (assumes ownership: will dec_ref iterator when done)
        public static IEnumerable<ada_node> EnumerateNodeIteratorAndFree(IntPtr iter)
        {
            if (iter == IntPtr.Zero) yield break;
            Native.ada_node_iterator_inc_ref(iter);
            try
            {
                IntPtr current = iter;
                while (current != IntPtr.Zero)
                {
                    ada_node e;
                    IntPtr next = Native.ada_node_iterator_next(current, out e);
                    yield return e;
                    if (next == IntPtr.Zero) break;
                    current = next;
                }
            }
            finally
            {
                Native.ada_node_iterator_dec_ref(iter);
            }
        }
    }

    // Lightweight managed wrappers for owned native resources
    public sealed class AdaContextHandle : SafeHandleZeroOrMinusOneIsInvalid
    {
        public AdaContextHandle() : base(true) { }
        public AdaContextHandle(IntPtr existing) : base(true) { SetHandle(existing); }

        public static AdaContextHandle Create()
        {
            IntPtr p = Native.ada_allocate_analysis_context();
            return p == IntPtr.Zero ? null : new AdaContextHandle(p);
        }

        protected override bool ReleaseHandle()
        {
            // ada_context_decref releases an ownership share
            Native.ada_context_decref(handle);
            return true;
        }
    }

    public sealed class EventHandlerHandle : SafeHandleZeroOrMinusOneIsInvalid
    {
        public EventHandlerHandle() : base(true) { }
        public EventHandlerHandle(IntPtr existing) : base(true) { SetHandle(existing); }

        protected override bool ReleaseHandle()
        {
            Native.ada_dec_ref_event_handler(handle);
            return true;
        }
    }

    public sealed class FileReaderHandle : SafeHandleZeroOrMinusOneIsInvalid
    {
        public FileReaderHandle() : base(true) { }
        public FileReaderHandle(IntPtr existing) : base(true) { SetHandle(existing); }

        protected override bool ReleaseHandle()
        {
            Native.ada_dec_ref_file_reader(handle);
            return true;
        }
    }

    public sealed class NodeArrayHandle : IDisposable
    {
        public IntPtr Ptr { get; }
        public NodeArrayHandle(IntPtr p) { Ptr = p; }
        public ada_node[] ToArray() => Native.ReadNodeArrayAndFree(Ptr);
        public void Dispose() => Native.ada_node_array_dec_ref(Ptr);
    }

    public sealed class GprProjectHandle : SafeHandleZeroOrMinusOneIsInvalid
