    // Higher-level convenience API (non-exhaustive)
    public static class Api
    {
        // Create and initialize a context. Returned handle owns a ref that will be released when disposed.
        public static AdaContextHandle CreateInitializedContext(string charset = null, FileReaderHandle fileReader = null, IntPtr unitProvider = default, EventHandlerHandle eventHandler = null, bool withTrivia = true, int tabStop = 8)
        {
            var ctx = AdaContextHandle.Create();
            if (ctx == null) return null;
            Native.ada_initialize_analysis_context(ctx.DangerousGetHandle(), charset, fileReader?.DangerousGetHandle() ?? IntPtr.Zero, unitProvider, eventHandler?.DangerousGetHandle() ?? IntPtr.Zero, withTrivia ? 1 : 0, tabStop);
            return ctx;
        }

        // Get a unit by filename (managed wrapper). Result is raw IntPtr (ownership remains with context).
        public static IntPtr GetUnitFromFile(AdaContextHandle context, string filename, string charset = null, bool reparse = false, ada_grammar_rule rule = ada_default_grammar_rule)
        {
            if (context == null || context.IsInvalid) return IntPtr.Zero;
            return Native.ada_get_analysis_unit_from_file(context.DangerousGetHandle(), filename, charset, reparse ? 1 : 0, rule);
        }

        // Get unit root node
        public static ada_node GetUnitRoot(IntPtr unit)
        {
            Native.ada_unit_root(unit, out ada_node n);
            return n;
        }

        // Get textual image of a node
        public static string NodeImage(ref ada_node node)
        {
            Native.ada_node_image(ref node, out ada_text t);
            try { return Native.AdaTextToManagedString(ref t); }
            finally { Native.ada_destroy_text(ref t); }
        }

        // Unparse a rewriting unit to string (frees native ada_text bytes)
        public static string UnparseRewritingUnit(IntPtr unitHandle)
        {
            Native.ada_rewriting_unit_unparse(unitHandle, out ada_text t);
            try { return Native.AdaTextToManagedString(ref t); }
            finally { Native.ada_destroy_text(ref t); }
        }
    }
